import re

lines = [line.strip() for line in data.strip().split("\n") if line.strip()]

rows = []
for line in lines:
    tokens = [t for t in line.split() if t]
    if len(tokens) >= 8:
        db = tokens[0]
        name = tokens[1]
        p_type = tokens[2]
        definer = tokens[3]
        modified = tokens[4] + " " + tokens[5]
        created = tokens[6] + " " + tokens[7]
        sec_type = tokens[8]
        rows.append((db, name, p_type, definer, modified, created, sec_type))

# Sort by modified timestamp descending (most recent first)
rows.sort(key=lambda x: x[4], reverse=True)

with open(r"c:\xampp\htdocs\pos\scratch\sorted_procedures.md", "w") as f:
    f.write("| Db | Name | Type | Definer | Modified | Created | Security Type |\n")
    f.write("| --- | --- | --- | --- | --- | --- | --- |\n")
    for r in rows:
        f.write(f"| {r[0]} | {r[1]} | {r[2]} | {r[3]} | {r[4]} | {r[5]} | {r[6]} |\n")
